// Ordered list of icon IDs shown in the picker (6 × 10 = 60)
const PICKER_ICONS = [
    "code", "globe", "compass", "flag", "planet", "shield",
    "heart", "bookmark", "suitcase", "creditcard", "chartline", "checkbox",
    "bulb", "coffee", "cupcake", "leaf", "sun", "waterdrop",
    "firstaid", "shuffle", "show", "reload", "package", "radio",
    "users", "wavycheck", "wavy", "circle", "square", "triangle",
    "view_3d", "rotate_3d", "activity", "ai_brain", "airplane", "barns",
    "biscuit", "building", "china_temple", "claude", "constellation", "truck",
    "global", "laurel", "money_bag", "mortar", "origami", "perplexity",
    "plant", "receipt", "satellite", "saturn", "basket", "sticker",
    "study_lamp", "telescope", "tree_palm", "yoga",
];

export const ICON_PRESETS = PICKER_ICONS;

// ─── HELPERS ────────────────────────────────────────────────
export function resolveColor(colorId) {
    if (!colorId || colorId === 'white') return '#ffffff';
    const found = ICON_COLORS.find(c => c.id === colorId);
    return found ? found.value : '#ffffff';
}

// ─── ICON COMPONENT ─────────────────────────────────────────
export default function ProjectIcon({ name, size = 20, color, className = "" }) {
    const icon = ICONS[name] || ICONS.code;
    const strokeColor = color ? resolveColor(color) : undefined;

    return (
        <svg
            width={size}
            height={size}
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
            className={className}
            style={strokeColor ? { color: strokeColor } : undefined}
            xmlns="http://www.w3.org/2000/svg"
        >
            {icon.paths.map((d, i) => (
                <path key={i} d={d} />
            ))}
        </svg>
    );
}

// ─── ICON PICKER ────────────────────────────────────────────
export function IconPicker({ currentIcon, currentColor, onSelect, onClose }) {
    const [selectedIcon, setSelectedIcon] = useState(currentIcon || "code");
    const [selectedColor, setSelectedColor] = useState(currentColor || "white");

    const handleConfirm = () => {
        onSelect(selectedIcon, selectedColor);
        onClose();
    };

    const accent = resolveColor(selectedColor);

    return (
        <div
            className="fixed inset-0 z-[110] flex items-center justify-center bg-black/70 backdrop-blur-md animate-in fade-in duration-200"
            onClick={onClose}
        >
            <div className="w-full max-w-[380px] px-4" onClick={e => e.stopPropagation()}>
                <div className="bg-[#09090b] border border-white/10 shadow-2xl rounded-2xl overflow-hidden animate-in zoom-in-95 duration-200">

                    {/* Header */}
                    <div className="flex items-center justify-between px-5 pt-5 pb-4">
                        <span className="text-fluid-3xs uppercase tracking-[0.15em] text-zinc-500 font-bold font-mono">
                            Select Icon
                        </span>
                        <button
                            aria-label="Close"
                            onClick={onClose}
                            className="w-6 h-6 rounded-lg flex items-center justify-center text-zinc-600 hover:bg-white/[0.06] hover:text-zinc-300 transition-colors"
                        >
                            <CancelSquare size={14} className="shrink-0" />
                        </button>
                    </div>

                    <div className="px-5 pb-5 space-y-5">

                        {/* Preview */}
                        <div className="flex justify-center">
                            <div
                                className="w-[72px] h-[72px] rounded-2xl flex items-center justify-center transition-all duration-300"
                                style={{
                                    background: `radial-gradient(circle at 40% 35%, ${accent}18 0%, #09090b 70%)`,
                                    border: `1px solid ${accent}30`,
                                    boxShadow: `0 0 32px ${accent}18`,
                                }}
                            >
                                <ProjectIcon name={selectedIcon} size={32} color={selectedColor} />
                            </div>
                        </div>

                        {/* Color swatches */}
                        <div className="flex items-center justify-center gap-3">
                            {ICON_COLORS.map(c => {
                                const isActive = selectedColor === c.id;
                                return (
                                    <button
                                        key={c.id}
                                        onClick={() => setSelectedColor(c.id)}
                                        title={c.label}
                                        className="relative w-7 h-7 rounded-full transition-all duration-200 flex items-center justify-center"
                                        style={{
                                            background: isActive
                                                ? `radial-gradient(circle, ${c.value}cc 0%, ${c.value}66 100%)`
                                                : `radial-gradient(circle, ${c.value}55 0%, ${c.value}33 100%)`,
                                            boxShadow: isActive ? `0 0 10px ${c.value}50` : 'none',
                                            transform: isActive ? 'scale(1.15)' : 'scale(1)',
                                            outline: isActive ? `1.5px solid ${c.value}60` : 'none',
                                            outlineOffset: '2px',
                                        }}
                                    />
                                );
                            })}
                        </div>

                        <div className="h-px bg-white/[0.05]" />

                        {/* Icon grid — 6 cols */}
                        <div className="grid grid-cols-6 gap-1.5">
                            {PICKER_ICONS.map(iconName => {
                                const isActive = selectedIcon === iconName;
                                return (
                                    <button
                                        key={iconName}
                                        onClick={() => setSelectedIcon(iconName)}
                                        aria-label={iconName}
                                        className="aspect-square rounded-xl flex items-center justify-center transition-all duration-150"
                                        style={isActive ? {
                                            background: `${accent}20`,
                                            border: `1px solid ${accent}40`,
                                            color: accent,
                                        } : {
                                            background: 'rgba(255,255,255,0.04)',
                                            border: '1px solid rgba(255,255,255,0.06)',
                                            color: '#52525b',
                                        }}
                                        onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = 'rgba(255,255,255,0.08)'; }}
                                        onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'rgba(255,255,255,0.04)'; }}
                                    >
                                        <ProjectIcon name={iconName} size={16} color={isActive ? selectedColor : undefined} />
                                    </button>
                                );
                            })}
                        </div>

                        {/* Apply */}
                        <button
                            onClick={handleConfirm}
                            className="w-full py-2.5 rounded-xl border border-white/10 bg-white/[0.06] text-white text-fluid-3xs uppercase tracking-[0.15em] font-bold font-mono hover:bg-white/[0.10] transition-colors"
                        >
                            Apply
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}
